     3→import { useCallback, useEffect, useState } from 'react';
     4→import { useTranslation } from 'react-i18next';
     5→import {
     6→  fetchBalanceSummary,
     7→  createTenantAccount,
     8→  useCurrencyStore,
     9→  SALARY_CURRENCIES,
    10→  CURRENCY_SYMBOLS,
    11→  type BalanceSummaryDto,
    12→  type TenantAccountBalanceSummaryDto,
    13→  type SalaryCurrency,
    14→} from '@/entities/balance';
    15→import { AccountsHeader, type AccountTab } from './AccountsHeader';
    16→import { AccountTable } from './AccountTable';
    17→import { TransactionHistory } from './TransactionHistory';
    18→import { WithdrawalModal } from './WithdrawalModal';
    19→import { InvoiceModal } from './InvoiceModal';
    20→import './accounts-page.scss';
    21→
    22→function getAccountTotal(
    23→  account: TenantAccountBalanceSummaryDto,
    24→  currency: SalaryCurrency,
    25→): string {
    26→  switch (currency) {
    27→    case 'USD': return account.totalUSD;
    28→    case 'EUR': return account.totalEUR;
    29→    case 'RUB': return account.totalRUB;
    30→  }
    31→}
    32→
    33→function formatTotal(value: string, currency: SalaryCurrency): string {
    34→  const num = parseFloat(value);
    35→  if (isNaN(num)) return `${CURRENCY_SYMBOLS[currency]}0`;
    36→  return `${CURRENCY_SYMBOLS[currency]}${new Intl.NumberFormat('en-US', {
    37→    minimumFractionDigits: 0,
    38→    maximumFractionDigits: 0,
    39→  }).format(num)}`;
    40→}
    41→
    42→export default function AccountsPage() {
    43→  const { t } = useTranslation('accounts');
    44→  const [data, setData] = useState<BalanceSummaryDto | null>(null);
    45→  const [selectedAccountId, setSelectedAccountId] = useState<string | null>(null);
    46→  const currency = useCurrencyStore((s) => s.currency);
    47→  const setCurrency = useCurrencyStore((s) => s.setCurrency);
    48→  const [loading, setLoading] = useState(true);
    49→  const [activeTab, setActiveTab] = useState<AccountTab>('balances');
    50→  const [withdrawOpen, setWithdrawOpen] = useState(false);
    51→  const [invoiceOpen, setInvoiceOpen] = useState(false);
    52→
    53→  const loadData = useCallback(async () => {
    54→    try {
    55→      const res = await fetchBalanceSummary();
    56→      setData(res);
    57→      return res;
    58→    } catch {
    59→      return null;
    60→    }
    61→  }, []);
    62→
    63→  useEffect(() => {
    64→    let cancelled = false;
    65→    fetchBalanceSummary()
    66→      .then((res) => {
    67→        if (cancelled) return;
    68→        setData(res);
    69→        if (res.accounts.length > 0) {
    70→          setSelectedAccountId(res.accounts[0].tenantAccountId);
    71→        }
    72→      })
    73→      .catch(() => {})
    74→      .finally(() => {
    75→        if (!cancelled) setLoading(false);
    76→      });
    77→    return () => { cancelled = true; };
    78→  }, []);
    79→
    80→  const handleCreate = useCallback(async (name: string) => {
    81→    const created = await createTenantAccount(name);
    82→    const refreshed = await loadData();
    83→    if (refreshed) {
    84→      const newAccount = refreshed.accounts.find(
    85→        (a) => a.tenantAccountId === created.id,
    86→      );
    87→      if (newAccount) {
    88→        setSelectedAccountId(newAccount.tenantAccountId);
    89→      }
    90→    }
    91→  }, [loadData]);
    92→
    93→  const selectedAccount =
    94→    data?.accounts.find((a) => a.tenantAccountId === selectedAccountId) ?? null;
    95→
    96→  const accountCount = data?.accounts.length ?? 0;
    97→  const assetCount = selectedAccount?.balances.length ?? 0;
    98→  const totalDisplay = selectedAccount
    99→    ? formatTotal(getAccountTotal(selectedAccount, currency), currency)
   100→    : '—';
   101→
   102→  const handleCurrencyCycle = useCallback(() => {
   103→    const idx = SALARY_CURRENCIES.indexOf(currency);
   104→    setCurrency(SALARY_CURRENCIES[(idx + 1) % SALARY_CURRENCIES.length]);
   105→  }, [currency, setCurrency]);
   106→
   107→  return (
   108→    <div className="accounts-page">
   109→      <AccountsHeader
   110→        accountCount={accountCount}
   111→        accounts={data?.accounts ?? []}
   112→        selectedAccountId={selectedAccountId}
   113→        onAccountChange={setSelectedAccountId}
   114→        onCreate={handleCreate}
   115→        activeTab={activeTab}
   116→        onTabChange={setActiveTab}
   117→      />
   118→
   119→      {activeTab === 'balances' && (
   120→        <>
   121→          {/* Balance Summary Card — desktop only */}
   122→          <div className="balance-summary">
   123→            <div className="balance-summary__left">
   124→              <span className="balance-summary__label">{t('totalBalance')}</span>
   125→              <div className="balance-summary__amount">
   126→                <span className="balance-summary__value">{totalDisplay}</span>
   127→                <span className="balance-summary__currency-label">{currency}</span>
   128→              </div>
   129→              <span className="balance-summary__subtitle">
   130→                {t('acrossAssets', { count: assetCount })}
   131→                {' · '}
   132→                {t('displayCurrency')}:&nbsp;
   133→                <button
   134→                  type="button"
   135→                  className="balance-summary__currency-switch"
   136→                  onClick={handleCurrencyCycle}
   137→                >
   138→                  {currency}
   139→                </button>
   140→              </span>
   141→            </div>
   142→            <div className="balance-summary__actions">
   143→              <button
   144→                type="button"
   145→                className="balance-summary__action-btn"
   146→                onClick={() => setInvoiceOpen(true)}
   147→              >
   148→                {t('createInvoice')}
   149→              </button>
   150→              <button type="button" className="balance-summary__action-btn">
   151→                {t('addFunds')}
   152→              </button>
   153→              <button
   154→                type="button"
   155→                className="balance-summary__action-btn"
   156→                onClick={() => setWithdrawOpen(true)}
   157→              >
   158→                {t('withdraw')}
   159→              </button>
   160→            </div>
   161→          </div>
   162→
   163→          <AccountTable
   164→            account={selectedAccount}
   165→            currency={currency}
   166→            onCurrencyChange={setCurrency}
   167→            loading={loading}
   168→          />
   169→        </>
   170→      )}
   171→
   172→      {activeTab === 'history' && <TransactionHistory />}
   173→
   174→      {invoiceOpen && selectedAccount && (
   175→        <InvoiceModal
   176→          tenantAccountId={selectedAccount.tenantAccountId}
   177→          onClose={() => setInvoiceOpen(false)}
   178→        />
   179→      )}
   180→
   181→      {withdrawOpen && selectedAccount && (
   182→        <WithdrawalModal
   183→          tenantAccountId={selectedAccount.tenantAccountId}
   184→          balances={selectedAccount.balances}
   185→          onClose={() => {
   186→            setWithdrawOpen(false);
   187→            loadData();
   188→          }}
   189→        />
   190→      )}
   191→    </div>
   192→  );
   193→}
