     3→import { useCallback, useEffect, useLayoutEffect, useRef, useState } from 'react';
     4→import { useTranslation } from 'react-i18next';
     5→import type { TenantAccountBalanceSummaryDto } from '@/entities/balance';
     6→import {
     7→  Modal,
     8→  ModalTitle,
     9→  ModalLabel,
    10→  ModalError,
    11→  ModalActions,
    12→  ModalButton,
    13→} from '@/shared/ui';
    14→import './accounts-header.scss';
    15→
    16→export type AccountTab = 'balances' | 'history';
    17→
    18→interface AccountsHeaderProps {
    19→  accounts: TenantAccountBalanceSummaryDto[];
    20→  selectedAccountId: string | null;
    21→  onAccountChange: (id: string) => void;
    22→  onCreate: (name: string) => Promise<void>;
    23→  accountCount: number;
    24→  activeTab: AccountTab;
    25→  onTabChange: (tab: AccountTab) => void;
    26→}
    27→
    28→function AccountAvatar({ name }: { name: string }) {
    29→  const letter = name.charAt(0).toUpperCase();
    30→  return <span className="accounts-header__avatar">{letter}</span>;
    31→}
    32→
    33→const MAX_ACCOUNTS = 3;
    34→
    35→export function AccountsHeader({
    36→  accounts,
    37→  selectedAccountId,
    38→  onAccountChange,
    39→  onCreate,
    40→  accountCount,
    41→  activeTab,
    42→  onTabChange,
    43→}: AccountsHeaderProps) {
    44→  const { t } = useTranslation('accounts');
    45→  const [dropdownOpen, setDropdownOpen] = useState(false);
    46→  const [modalOpen, setModalOpen] = useState(false);
    47→  const [accountName, setAccountName] = useState('');
    48→  const [creating, setCreating] = useState(false);
    49→  const [error, setError] = useState('');
    50→  const desktopDropdownRef = useRef<HTMLDivElement>(null);
    51→  const mobileDropdownRef = useRef<HTMLDivElement>(null);
    52→  const inputRef = useRef<HTMLInputElement>(null);
    53→  const tabsRef = useRef<HTMLElement>(null);
    54→  const tabRefs = useRef<Record<AccountTab, HTMLButtonElement | null>>({ balances: null, history: null });
    55→  const [indicator, setIndicator] = useState({ left: 0, width: 0 });
    56→
    57→  const selectedAccount = accounts.find(
    58→    (a) => a.tenantAccountId === selectedAccountId,
    59→  );
    60→
    61→  useLayoutEffect(() => {
    62→    const btn = tabRefs.current[activeTab];
    63→    const nav = tabsRef.current;
    64→    if (!btn || !nav) return;
    65→    const navRect = nav.getBoundingClientRect();
    66→    const btnRect = btn.getBoundingClientRect();
    67→    setIndicator({ left: btnRect.left - navRect.left, width: btnRect.width });
    68→  }, [activeTab]);
    69→
    70→  useEffect(() => {
    71→    function onPointerDown(e: PointerEvent) {
    72→      const target = e.target as Node;
    73→      if (!desktopDropdownRef.current?.contains(target) && !mobileDropdownRef.current?.contains(target)) {
    74→        setDropdownOpen(false);
    75→      }
    76→    }
    77→    document.addEventListener('pointerdown', onPointerDown);
    78→    return () => document.removeEventListener('pointerdown', onPointerDown);
    79→  }, []);
    80→
    81→  useEffect(() => {
    82→    if (modalOpen) {
    83→      requestAnimationFrame(() => inputRef.current?.focus());
    84→    }
    85→  }, [modalOpen]);
    86→
    87→  const openModal = useCallback(() => {
    88→    setAccountName('');
    89→    setError('');
    90→    setModalOpen(true);
    91→  }, []);
    92→
    93→  const closeModal = useCallback(() => {
    94→    if (creating) return;
    95→    setModalOpen(false);
    96→  }, [creating]);
    97→
    98→  const handleSubmit = useCallback(async () => {
    99→    const trimmed = accountName.trim();
   100→    if (!trimmed || creating) return;
   101→
   102→    setCreating(true);
   103→    setError('');
   104→    try {
   105→      await onCreate(trimmed);
   106→      setModalOpen(false);
   107→    } catch (err: unknown) {
   108→      const message =
   109→        err instanceof Error ? err.message : t('createModal.maxReached');
   110→      setError(message);
   111→    } finally {
   112→      setCreating(false);
   113→    }
   114→  }, [accountName, creating, onCreate, t]);
   115→
   116→  const atLimit = accountCount >= MAX_ACCOUNTS;
   117→
   118→  return (
   119→    <>
   120→      {/* Desktop Header */}
   121→      <div className="accounts-header">
   122→        <div className="accounts-header__left">
   123→          <h1 className="accounts-header__title">{t('title')}</h1>
   124→          <nav ref={tabsRef} className="accounts-header__tabs">
   125→            <button
   126→              ref={(el) => { tabRefs.current.balances = el; }}
   127→              type="button"
   128→              className={`accounts-header__tab${activeTab === 'balances' ? ' accounts-header__tab--active' : ''}`}
   129→              onClick={() => onTabChange('balances')}
   130→            >
   131→              {t('tabs.balances')}
   132→            </button>
   133→            <button
   134→              ref={(el) => { tabRefs.current.history = el; }}
   135→              type="button"
   136→              className={`accounts-header__tab${activeTab === 'history' ? ' accounts-header__tab--active' : ''}`}
   137→              onClick={() => onTabChange('history')}
   138→            >
   139→              {t('tabs.history')}
   140→            </button>
   141→            <span
   142→              className="accounts-header__tab-indicator"
   143→              style={{ left: indicator.left, width: indicator.width }}
   144→            />
   145→          </nav>
   146→        </div>
   147→
   148→        <div className="accounts-header__right">
   149→          <div ref={desktopDropdownRef} className="accounts-header__dropdown-wrap">
   150→            <button
   151→              type="button"
   152→              className={`accounts-header__dropdown${dropdownOpen ? ' accounts-header__dropdown--open' : ''}`}
   153→              onClick={() => setDropdownOpen((v) => !v)}
   154→            >
   155→              <span className="accounts-header__avatar">{accountCount}</span>
   156→              <span className="accounts-header__dropdown-text">
   157→                {selectedAccount?.tenantAccountName ?? '—'}
   158→              </span>
   159→              <svg
   160→                className={`accounts-header__dropdown-chevron${dropdownOpen ? ' accounts-header__dropdown-chevron--open' : ''}`}
   161→                width="16"
   162→                height="16"
   163→                viewBox="0 0 16 16"
   164→                fill="none"
   165→              >
   166→                <path
   167→                  d="M4 6L8 10L12 6"
   168→                  stroke="currentColor"
   169→                  strokeWidth="1.5"
   170→                  strokeLinecap="round"
   171→                  strokeLinejoin="round"
   172→                />
   173→              </svg>
   174→            </button>
   175→            {dropdownOpen && (
   176→              <ul className="accounts-header__dropdown-menu">
   177→                {accounts.map((acc) => (
   178→                  <li key={acc.tenantAccountId}>
   179→                    <button
   180→                      type="button"
   181→                      className={`accounts-header__dropdown-option${
   182→                        acc.tenantAccountId === selectedAccountId
   183→                          ? ' accounts-header__dropdown-option--active'
   184→                          : ''
   185→                      }`}
   186→                      onClick={() => {
   187→                        onAccountChange(acc.tenantAccountId);
   188→                        setDropdownOpen(false);
   189→                      }}
   190→                    >
   191→                      <AccountAvatar name={acc.tenantAccountName} />
   192→                      {acc.tenantAccountName}
   193→                    </button>
   194→                  </li>
   195→                ))}
   196→                {!atLimit && (
   197→                  <li className="accounts-header__dropdown-divider" />
   198→                )}
   199→                {!atLimit && (
   200→                  <li>
   201→                    <button
   202→                      type="button"
   203→                      className="accounts-header__dropdown-option accounts-header__dropdown-option--create"
   204→                      onClick={() => {
   205→                        setDropdownOpen(false);
   206→                        openModal();
